mapper.select:
SELECT COALESCE(SUM(ms.total_cost), 0) AS bill , ym.`year_month` AS yearMonth , 'AWS' AS csp FROM (
SELECT #{prevMonth} COLLATE utf8mb4_unicode_ci AS `year_month`
) AS ym LEFT JOIN ( SELECT ms.`year_month` , SUM(ms.total_cost) AS total_cost FROM monthly_summation ms WHERE ms.csp = 'AWS' AND ms.project_cd IN
#{selectedProject}
AND 1=0
AND ms.`year_month` IN
#{prevMonth}
GROUP BY ms.`year_month` ) ms ON ym.`year_month` = ms.`year_month` GROUP BY ym.`year_month`
UNION ALL
SELECT COALESCE(SUM(nvd_latest.demand_amount), 0) / ${krwPerUsd} AS bill , nvd_latest.demand_month AS yearMonth , 'NCP' AS csp FROM ( SELECT n1.demand_month, n1.instance_no, n1.demand_amount FROM ncp_cost_vm_month n1 INNER JOIN ( SELECT demand_month, instance_no, MAX(id) AS latest_id FROM ncp_cost_vm_month WHERE demand_month IN
#{prevMonth}
GROUP BY demand_month, instance_no ) n2 ON n1.demand_month = n2.demand_month AND n1.instance_no = n2.instance_no AND n1.id = n2.latest_id ) nvd_latest INNER JOIN servicegroup_meta sm ON nvd_latest.instance_no COLLATE utf8mb4_unicode_ci = sm.csp_instanceid COLLATE utf8mb4_unicode_ci AND sm.csp_type = 'NCP' WHERE 1=1
AND sm.service_cd IN
#{selectedProject}
AND 1=0
GROUP BY nvd_latest.demand_month
UNION ALL
SELECT COALESCE(SUM(cost), 0) AS bill , yearMonth , 'AZURE' AS csp FROM (
SELECT COALESCE(SUM(acvd.pre_tax_cost), 0) / ${krwPerUsd} AS cost , #{prevMonth} AS yearMonth FROM azure_cost_vm_daily acvd INNER JOIN servicegroup_meta sm ON acvd.vm_id COLLATE utf8mb4_unicode_ci = sm.vm_uid COLLATE utf8mb4_unicode_ci AND sm.csp_type = 'AZURE'
AND sm.service_cd IN
#{selectedProject}
WHERE DATE_FORMAT(acvd.usage_date, '%Y%m') = #{prevMonth}
) AS azure_data WHERE 1=1
AND 1=0
GROUP BY yearMonth
UNION ALL
SELECT COALESCE(SUM(ms.total_cost), 0) AS bill , ms.`year_month` AS yearMonth , 'GCP' AS csp FROM monthly_summation ms WHERE ms.csp = 'GCP' AND ms.project_cd IN
#{selectedProject}
AND ms.`year_month` IN
#{prevMonth}
AND 1=0
GROUP BY ms.`year_month`
ORDER BY yearMonth DESC, csp

SELECT co.lineitem_usageaccountid AS accountID , co.lineitem_productcode AS productID , sm.csp_type AS csp , SUM(co.lineitem_unblendedcost) AS bill , co.lineitem_resourceid AS resourceID FROM tbl_table_billing_detail_${year_month} co INNER JOIN servicegroup_meta sm ON co.lineitem_resourceid = sm.csp_instanceid AND sm.csp_type = 'AWS'
AND sm.service_cd IN
#{selectedProject}
AND co.lineitem_usagestartdate >= #{curMonthStartDate} AND co.lineitem_usageenddate < #{curMonthEndDate}
AND 1=0
GROUP BY co.lineitem_usageaccountid, co.lineitem_productcode, sm.csp_type, co.lineitem_resourceid

SELECT acvd.tenant_id AS accountID , acvd.vm_id AS productID , 'AZURE' AS csp , SUM(acvd.pre_tax_cost) / ${krwPerUsd} AS bill , acvd.resource_id AS resourceID FROM azure_cost_vm_daily acvd INNER JOIN servicegroup_meta sm ON acvd.vm_id COLLATE utf8mb4_unicode_ci = sm.vm_uid COLLATE utf8mb4_unicode_ci AND sm.csp_type = 'AZURE'
AND sm.service_cd IN
#{selectedProject}
WHERE DATE_FORMAT(acvd.usage_date, '%Y%m') = #{year_month}
AND 1=0
GROUP BY acvd.tenant_id, acvd.vm_id, acvd.resource_id

SELECT raw.billing_account_id AS accountID , raw.service_description AS productID , 'GCP' AS csp , SUM(raw.cost) / ${krwPerUsd} AS bill , raw.csp_instanceid AS resourceID FROM gcp_billing_raw raw INNER JOIN servicegroup_meta sm ON sm.csp_type = 'GCP' AND sm.csp_instanceid COLLATE utf8mb4_uca1400_ai_ci = raw.csp_instanceid
AND sm.service_cd COLLATE utf8mb4_uca1400_ai_ci IN
#{selectedProject}
WHERE raw.invoice_month = #{year_month}
AND 1=0
GROUP BY raw.billing_account_id, raw.service_description, raw.csp_instanceid
